# Workflow Cleaner, simplifié
class CleanerAgent:
    def refactor_module(self, legacy_path: str, target_arch: dict):
        old_behavior = self.capture_behavior(legacy_path)
        new_code = self.generate_target(legacy_path, target_arch)
        new_behavior = self.execute(new_code)

        if not self.behaviors_equivalent(old_behavior, new_behavior):
            return self.escalate_to_human(legacy_path, diff=...)

        return self.create_pr(new_code, tests=self.generate_tests(...))

