// Strangler facade : le client appelle l'API moderne,
// le routeur décide si la requête va vers le legacy ou la nouvelle impl
@RestController
public class CustomerController {
    @Autowired private CobolGateway legacy;
    @Autowired private CustomerServiceV2 modern;
    @Autowired private FeatureFlag flags;

    @GetMapping("/customers/{id}")
    public Customer get(@PathVariable String id) {
        if (flags.isEnabled("customer-v2", id)) {
            return modern.findById(id);
        }
        return legacy.callCobolModule("CUSTGET", id);
    }
}
